 17→/// DICOM TUI Viewer - View DICOM file tags in a terminal interface
 18→#[derive(Parser, Debug)]
 19→#[command(author, version, about, long_about = None)]
 20→struct Args {
 21→    /// Compare two DICOM files (baseline vs modified)
 22→    #[arg(short = 'd', long, value_names = ["BASELINE", "MODIFIED"], num_args = 2)]
 23→    diff: Option<Vec<PathBuf>>,
 24→
 25→    /// Path to the DICOM file to view (used when --diff is not specified)
 26→    #[arg(value_name = "FILE", required_unless_present = "diff")]
 27→    file: Option<PathBuf>,
 28→}
 29→
 30→fn validate_path(path: &Path) -> Result<(), Box<dyn std::error::Error>> {
 31→    if !path.exists() {
 32→        return Err(format!("file not found: {}", path.display()).into());
 33→    }
 34→    if !path.is_file() {
 35→        return Err(format!("not a file: {}", path.display()).into());
 36→    }
 37→    let mut file = std::fs::File::open(path)?;
 38→    let mut buf = [0u8; 132];
 39→    use std::io::Read;
 40→    if file.read(&mut buf)? < 132 || &buf[128..132] != b"DICM" {
 41→        return Err(format!("not a valid DICOM file: {}", path.display()).into());
 42→    }
 43→    Ok(())
 44→}
 45→
 46→fn main() -> Result<(), Box<dyn std::error::Error>> {
 47→    let args = Args::parse();
 48→
 49→    let picker = Picker::from_query_stdio().ok();
 50→
 51→    let (tags, file_name, modified_name, validation_result, sop_class, diff_mode, dicom_file_path) =
 52→        if let Some(diff_files) = &args.diff {
 53→            if diff_files.len() != 2 {
 54→                return Err("--diff requires exactly two file arguments".into());
 55→            }
 56→            let baseline_path = &diff_files[0];
 57→            let modified_path = &diff_files[1];
 58→            validate_path(baseline_path)?;
 59→            validate_path(modified_path)?;
 60→
 61→            let tags = dicom::compare_dicom_files(baseline_path, modified_path)?;
 62→
 63→            let baseline_name = baseline_path
 64→                .file_name()
 65→                .map(|s| s.to_string_lossy().to_string())
 66→                .unwrap_or_else(|| baseline_path.to_string_lossy().to_string());
 67→            let modified_name = modified_path
 68→                .file_name()
 69→                .map(|s| s.to_string_lossy().to_string())
 70→                .unwrap_or_else(|| modified_path.to_string_lossy().to_string());
 71→
 72→            let sop_class =
 73→                validation::get_sop_class(baseline_path).unwrap_or(validation::SopClass::Unknown);
 74→            let validation_result = validation::validate_type1_fields(baseline_path)
 75→                .unwrap_or(validation::ValidationResult::NotApplicable);
 76→
 77→            (
 78→                tags,
 79→                baseline_name,
 80→                Some(modified_name),
 81→                validation_result,
 82→                sop_class,
 83→                true,
 84→                Some(baseline_path.clone()),
 85→            )
 86→        } else {
 87→            let file = args
 88→                .file
 89→                .ok_or("Either --diff with two files or a single file argument is required")?;
 90→
 91→            validate_path(&file)?;
 92→            let obj = ::dicom::object::open_file(&file)?;
 93→            let tags = dicom::extract_tags(&obj);
 94→            let sop_class = validation::get_sop_class_from_obj(&obj);
 95→            let validation_result = validation::validate_type1_fields_from_obj(&obj);
 96→
 97→            let file_name = file
 98→                .file_name()
 99→                .map(|s| s.to_string_lossy().to_string())
100→                .unwrap_or_else(|| file.to_string_lossy().to_string());
101→
102→            (
103→                tags,
104→                file_name,
105→                None,
106→                validation_result,
107→                sop_class,
108→                false,
109→                Some(file),
110→            )
111→        };
112→
113→    let mut app = App::new_with_diff(
114→        tags,
115→        file_name,
116→        modified_name,
117→        validation_result,
118→        sop_class,
119→        diff_mode,
120→        dicom_file_path,
121→        picker,
122→    );
123→
124→    enable_raw_mode()?;
125→    let mut stdout = io::stdout();
126→    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
127→    let backend = CrosstermBackend::new(stdout);
128→    let mut terminal = Terminal::new(backend)?;
129→
130→    let result = run_app(&mut terminal, &mut app);
131→
132→    disable_raw_mode()?;
133→    execute!(
134→        terminal.backend_mut(),
135→        LeaveAlternateScreen,
136→        DisableMouseCapture
137→    )?;
138→    terminal.show_cursor()?;
139→
140→    if let Err(err) = result {
141→        eprintln!("Error: {}", err);
142→        return Err(err.into());
143→    }
144→
145→    Ok(())
146→}
147→
148→fn run_app<B: Backend>(terminal: &mut Terminal<B>, app: &mut App) -> io::Result<()> {
149→    loop {
150→        terminal.draw(|frame| ui::render(frame, app))?;
151→
152→        app.handle_events()?;
153→
154→        if app.should_quit {
155→            return Ok(());
156→        }
157→    }
158→}
