 5→impl App {
 6→    pub fn filter_tags(&mut self) {
 7→        if self.search_query.is_empty() {
 8→            self.filtered_tags = None;
 9→            self.rebuild_visible_tags();
10→        } else {
11→            let query = self.search_query.to_lowercase();
12→            let filtered: Vec<DicomTag> = self
13→                .all_tags
14→                .iter()
15→                .filter(|tag| {
16→                    tag.tag.to_lowercase().contains(&query)
17→                        || tag.name.to_lowercase().contains(&query)
18→                })
19→                .cloned()
20→                .collect();
21→            self.filtered_tags = Some(filtered);
22→            self.rebuild_visible_tags();
23→        }
24→        self.reset_selection();
25→    }
26→
27→    pub fn reset_selection(&mut self) {
28→        if self.tags.is_empty() {
29→            self.table_state.select(None);
30→        } else {
31→            self.table_state.select(Some(0));
32→        }
33→    }
34→}
