 14→pub fn render(frame: &mut Frame, app: &mut App) {
 15→    let full_area = frame.area();
 16→
 17→    let (main_area, preview_area) = if app.show_preview {
 18→        let h_chunks = Layout::default()
 19→            .direction(Direction::Horizontal)
 20→            .constraints([Constraint::Percentage(50), Constraint::Percentage(50)])
 21→            .split(full_area);
 22→        (h_chunks[0], Some(h_chunks[1]))
 23→    } else {
 24→        (full_area, None)
 25→    };
 26→
 27→    let validation_height = if matches!(&app.validation_result, ValidationResult::Invalid(_)) {
 28→        4
 29→    } else {
 30→        3
 31→    };
 32→
 33→    let chunks = Layout::default()
 34→        .direction(Direction::Vertical)
 35→        .constraints([Constraint::Min(5), Constraint::Length(validation_height)])
 36→        .split(main_area);
 37→
 38→    let area = chunks[0];
 39→    let validation_area = chunks[1];
 40→
 41→    render_validation_pane(frame, validation_area, app);
 42→
 43→    if let Some(preview_area) = preview_area {
 44→        render_preview_pane(frame, preview_area, app);
 45→    }
 46→
 47→    let mut header_cells = vec![];
 48→    if app.diff_mode {
 49→        header_cells.push(
 50→            Cell::from(" ").style(
 51→                Style::default()
 52→                    .fg(Color::Yellow)
 53→                    .add_modifier(Modifier::BOLD),
 54→            ),
 55→        );
 56→    }
 57→    header_cells.extend(vec![
 58→        Cell::from("  Tag").style(
 59→            Style::default()
 60→                .fg(Color::Yellow)
 61→                .add_modifier(Modifier::BOLD),
 62→        ),
 63→        Cell::from("Name").style(
 64→            Style::default()
 65→                .fg(Color::Yellow)
 66→                .add_modifier(Modifier::BOLD),
 67→        ),
 68→        Cell::from("VR").style(
 69→            Style::default()
 70→                .fg(Color::Yellow)
 71→                .add_modifier(Modifier::BOLD),
 72→        ),
 73→        Cell::from("Value").style(
 74→            Style::default()
 75→                .fg(Color::Yellow)
 76→                .add_modifier(Modifier::BOLD),
 77→        ),
 78→    ]);
 79→    let header = Row::new(header_cells).height(1);
 80→
 81→    let rows: Vec<Row> = app
 82→        .tags
 83→        .iter()
 84→        .map(|tag| {
 85→            let indent = "  ".repeat(tag.depth);
 86→            let expand_indicator = if tag.is_expandable {
 87→                if tag.is_expanded {
 88→                    "▼ "
 89→                } else {
 90→                    "▶ "
 91→                }
 92→            } else {
 93→                "  "
 94→            };
 95→            let tag_display = format!("{}{}{}", indent, expand_indicator, tag.tag);
 96→
 97→            // Determine styles based on diff status
 98→            let (row_style, value_cell) = if let Some(diff_status) = &tag.diff_status {
 99→                match diff_status {
100→                    DiffStatus::Deleted => (
101→                        Style::default().fg(Color::Red),
102→                        Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Red)),
103→                    ),
104→                    DiffStatus::Added => (
105→                        Style::default().fg(Color::Green),
106→                        Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Green)),
107→                    ),
108→                    DiffStatus::Changed => {
109→                        // Use inline diff if baseline_value is available
110→                        let value_cell = if let Some(ref baseline) = tag.baseline_value {
111→                            let mut line = render_inline_diff(baseline, &tag.value);
112→                            if let Some(delta_ms) =
113→                                parse_dicom_datetime_delta_ms(&tag.vr, baseline, &tag.value)
114→                            {
115→                                let suffix = if delta_ms >= 0 {
116→                                    format!(" (+{} ms)", delta_ms)
117→                                } else {
118→                                    format!(" ({} ms)", delta_ms)
119→                                };
120→                                line.spans.push(Span::styled(
121→                                    suffix,
122→                                    Style::default().fg(Color::DarkGray),
123→                                ));
124→                            }
125→                            Cell::from(line)
126→                        } else {
127→                            // Fallback to simple blue text for backward compatibility
128→                            Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Blue))
129→                        };
130→                        (Style::default(), value_cell)
131→                    }
132→                    DiffStatus::Unchanged => (
133→                        Style::default(),
134→                        Cell::from(tag.value.as_str()).style(Style::default()),
135→                    ),
136→                }
137→            } else {
138→                // Normal mode: use private tag styling
139→                let base_style = if tag.is_private() {
140→                    Style::default().fg(Color::DarkGray)
141→                } else {
142→                    Style::default()
143→                };
144→                (base_style, Cell::from(tag.value.as_str()).style(base_style))
145→            };
146→
147→            let mut row_cells = vec![];
148→
149→            // Add diff indicator if in diff mode
150→            if app.diff_mode {
151→                let (indicator, indicator_style) = if let Some(diff_status) = &tag.diff_status {
152→                    match diff_status {
153→                        DiffStatus::Added => ("+", Style::default().fg(Color::Green)),
154→                        DiffStatus::Deleted => ("-", Style::default().fg(Color::Red)),
155→                        DiffStatus::Changed => ("M", Style::default().fg(Color::Blue)),
156→                        DiffStatus::Unchanged => (" ", Style::default()),
157→                    }
158→                } else {
159→                    (" ", Style::default())
160→                };
161→                row_cells.push(Cell::from(indicator).style(indicator_style));
162→            }
163→
164→            row_cells.extend(vec![
