 1→use super::loader::load_dicom_file;
 2→use super::tag::{DiffStatus, DicomTag};
 3→use std::collections::HashMap;
 4→use std::path::Path;
 5→
 6→pub fn compare_dicom_files<P: AsRef<Path>>(
 7→    baseline_path: P,
 8→    modified_path: P,
 9→) -> Result<Vec<DicomTag>, Box<dyn std::error::Error>> {
10→    let baseline_tags = load_dicom_file(baseline_path)?;
11→    let modified_tags = load_dicom_file(modified_path)?;
12→
13→    let mut baseline_map: HashMap<String, &DicomTag> = HashMap::new();
14→    for tag in &baseline_tags {
15→        baseline_map.insert(tag.tag.clone(), tag);
16→    }
17→
18→    let mut baseline_seen: std::collections::HashSet<String> = std::collections::HashSet::new();
19→    let mut result_tags: Vec<DicomTag> = Vec::new();
20→
21→    for modified_tag in &modified_tags {
22→        let tag_id = &modified_tag.tag;
23→        let mut diff_status = DiffStatus::Added;
24→        let mut baseline_value = None;
25→
26→        if let Some(baseline_tag) = baseline_map.get(tag_id) {
27→            baseline_seen.insert(tag_id.clone());
28→            if baseline_tag.value == modified_tag.value {
29→                diff_status = DiffStatus::Unchanged;
30→            } else {
31→                diff_status = DiffStatus::Changed;
32→                baseline_value = Some(baseline_tag.value.clone());
33→            }
34→        }
35→
36→        let mut result_tag = modified_tag.clone();
37→        result_tag.diff_status = Some(diff_status);
38→        result_tag.baseline_value = baseline_value;
39→        result_tags.push(result_tag);
40→    }
41→
42→    for baseline_tag in &baseline_tags {
43→        if !baseline_seen.contains(&baseline_tag.tag) {
44→            let mut deleted_tag = baseline_tag.clone();
45→            deleted_tag.diff_status = Some(DiffStatus::Deleted);
46→            result_tags.push(deleted_tag);
47→        }
48→    }
49→
50→    result_tags.sort_by(|a, b| a.tag.cmp(&b.tag));
51→
52→    Ok(result_tags)
53→}
