 1→use chrono::{NaiveDate, NaiveDateTime, NaiveTime};
 2→
 3→fn first_value(s: &str) -> &str {
 4→    s.split('\\').next().unwrap_or(s).trim()
 5→}
 6→
 7→pub fn parse_dicom_datetime_delta_ms(vr: &str, baseline: &str, modified: &str) -> Option<i64> {
 8→    let base = first_value(baseline);
 9→    let mod_ = first_value(modified);
10→    match vr {
11→        "DA" => {
12→            let d1 = NaiveDate::parse_from_str(base, "%Y%m%d").ok()?;
13→            let d2 = NaiveDate::parse_from_str(mod_, "%Y%m%d").ok()?;
14→            let delta_days = (d2 - d1).num_days();
15→            Some(delta_days * 24 * 3600 * 1000)
16→        }
17→        "TM" => {
18→            let t1 = parse_tm(base)?;
19→            let t2 = parse_tm(mod_)?;
20→            Some((t2 - t1).num_milliseconds())
21→        }
22→        "DT" => {
23→            let dt1 = parse_dt(base)?;
24→            let dt2 = parse_dt(mod_)?;
25→            Some((dt2 - dt1).num_milliseconds())
26→        }
27→        _ => None,
28→    }
29→}
30→
31→fn parse_tm(s: &str) -> Option<NaiveTime> {
32→    if s.contains('.') {
33→        NaiveTime::parse_from_str(s, "%H%M%S%.f").ok()
34→    } else {
35→        NaiveTime::parse_from_str(s, "%H%M%S").ok()
36→    }
37→}
38→
39→fn parse_dt(s: &str) -> Option<NaiveDateTime> {
40→    if s.contains('.') {
41→        NaiveDateTime::parse_from_str(s, "%Y%m%d%H%M%S%.f").ok()
42→    } else {
43→        NaiveDateTime::parse_from_str(s, "%Y%m%d%H%M%S").ok()
44→    }
45→}
