mod app;
mod dicom;
mod ui;
mod validation;

use app::App;
use clap::Parser;
use crossterm::{
    event::{DisableMouseCapture, EnableMouseCapture},
    execute,
    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
};
use ratatui::prelude::*;
use ratatui_image::picker::Picker;
use std::{io, path::Path, path::PathBuf};

/// DICOM TUI Viewer - View DICOM file tags in a terminal interface
#[derive(Parser, Debug)]
#[command(author, version, about, long_about = None)]
struct Args {
    /// Compare two DICOM files (baseline vs modified)
    #[arg(short = 'd', long, value_names = ["BASELINE", "MODIFIED"], num_args = 2)]
    diff: Option<Vec<PathBuf>>,

    /// Path to the DICOM file to view (used when --diff is not specified)
    #[arg(value_name = "FILE", required_unless_present = "diff")]
    file: Option<PathBuf>,
}

fn validate_path(path: &Path) -> Result<(), Box<dyn std::error::Error>> {
    if !path.exists() {
        return Err(format!("file not found: {}", path.display()).into());
    }
    if !path.is_file() {
        return Err(format!("not a file: {}", path.display()).into());
    }
    let mut file = std::fs::File::open(path)?;
    let mut buf = [0u8; 132];
    use std::io::Read;
    if file.read(&mut buf)? < 132 || &buf[128..132] != b"DICM" {
        return Err(format!("not a valid DICOM file: {}", path.display()).into());
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args = Args::parse();

    let picker = Picker::from_query_stdio().ok();

    let (tags, file_name, modified_name, validation_result, sop_class, diff_mode, dicom_file_path) =
        if let Some(diff_files) = &args.diff {
            if diff_files.len() != 2 {
                return Err("--diff requires exactly two file arguments".into());
            }
            let baseline_path = &diff_files[0];
            let modified_path = &diff_files[1];
            validate_path(baseline_path)?;
            validate_path(modified_path)?;

            let tags = dicom::compare_dicom_files(baseline_path, modified_path)?;

            let baseline_name = baseline_path
                .file_name()
                .map(|s| s.to_string_lossy().to_string())
                .unwrap_or_else(|| baseline_path.to_string_lossy().to_string());
            let modified_name = modified_path
                .file_name()
                .map(|s| s.to_string_lossy().to_string())
                .unwrap_or_else(|| modified_path.to_string_lossy().to_string());

            let sop_class =
                validation::get_sop_class(baseline_path).unwrap_or(validation::SopClass::Unknown);
            let validation_result = validation::validate_type1_fields(baseline_path)
                .unwrap_or(validation::ValidationResult::NotApplicable);

            (
                tags,
                baseline_name,
                Some(modified_name),
                validation_result,
                sop_class,
                true,
                Some(baseline_path.clone()),
            )
        } else {
            let file = args
                .file
                .ok_or("Either --diff with two files or a single file argument is required")?;

            validate_path(&file)?;
            let obj = ::dicom::object::open_file(&file)?;
            let tags = dicom::extract_tags(&obj);
            let sop_class = validation::get_sop_class_from_obj(&obj);
            let validation_result = validation::validate_type1_fields_from_obj(&obj);

            let file_name = file
                .file_name()
                .map(|s| s.to_string_lossy().to_string())
                .unwrap_or_else(|| file.to_string_lossy().to_string());

            (
                tags,
                file_name,
                None,
                validation_result,
                sop_class,
                false,
                Some(file),
            )
        };

    let mut app = App::new_with_diff(
        tags,
        file_name,
        modified_name,
        validation_result,
        sop_class,
        diff_mode,
        dicom_file_path,
        picker,
    );

    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    let result = run_app(&mut terminal, &mut app);

    disable_raw_mode()?;
    execute!(
        terminal.backend_mut(),
        LeaveAlternateScreen,
        DisableMouseCapture
    )?;
    terminal.show_cursor()?;

    if let Err(err) = result {
        eprintln!("Error: {}", err);
        return Err(err.into());
    }

    Ok(())
}

fn run_app<B: Backend>(terminal: &mut Terminal<B>, app: &mut App) -> io::Result<()> {
    loop {
        terminal.draw(|frame| ui::render(frame, app))?;

        app.handle_events()?;

        if app.should_quit {
            return Ok(());
        }
    }
}

use crate::dicom::DicomTag;
use crate::validation::{SopClass, ValidationResult};
use ratatui::layout::Rect;
use ratatui::widgets::TableState;
use ratatui_image::picker::Picker;
use ratatui_image::protocol::StatefulProtocol;
use std::path::PathBuf;

pub struct App {
    pub tags: Vec<DicomTag>,
    pub all_tags: Vec<DicomTag>,
    pub filtered_tags: Option<Vec<DicomTag>>,
    pub table_state: TableState,
    pub should_quit: bool,
    pub file_name: String,
    pub diff_mode: bool,
    pub modified_name: Option<String>,
    pub search_mode: bool,
    pub search_query: String,
    pub validation_result: ValidationResult,
    pub sop_class: SopClass,
    pub table_area: Rect,
    pub show_preview: bool,
    pub preview_image: Option<StatefulProtocol>,
    pub preview_error: Option<String>,
    pub dicom_file_path: Option<PathBuf>,
    pub picker: Option<Picker>,
}

impl App {
    pub fn new(
        tags: Vec<DicomTag>,
        file_name: String,
        validation_result: ValidationResult,
        sop_class: SopClass,
    ) -> Self {
        Self::new_with_diff(tags, file_name, None, validation_result, sop_class, false, None, None)
    }

    pub fn new_with_diff(
        tags: Vec<DicomTag>,
        file_name: String,
        modified_name: Option<String>,
        validation_result: ValidationResult,
        sop_class: SopClass,
        diff_mode: bool,
        dicom_file_path: Option<PathBuf>,
        picker: Option<Picker>,
    ) -> Self {
        let mut table_state = TableState::default();
        let visible_tags = Self::build_visible_tags_from(&tags);
        if !visible_tags.is_empty() {
            table_state.select(Some(0));
        }

        let mut app = Self {
            tags: visible_tags,
            all_tags: tags,
            filtered_tags: None,
            table_state,
            should_quit: false,
            file_name,
            diff_mode,
            modified_name,
            search_mode: false,
            search_query: String::new(),
            validation_result,
            sop_class,
            table_area: Rect::default(),
            show_preview: true,
            preview_image: None,
            preview_error: None,
            dicom_file_path,
            picker,
        };
        app.decode_preview();
        app
    }
}

