  5→impl App {
  6→    pub(super) fn build_visible_tags_from(tags: &[DicomTag]) -> Vec<DicomTag> {
  7→        let mut visible = Vec::new();
  8→        Self::collect_visible_tags(tags, &mut visible);
  9→        visible
 10→    }
 11→
 12→    fn collect_visible_tags(tags: &[DicomTag], visible: &mut Vec<DicomTag>) {
 13→        for tag in tags {
 14→            visible.push(tag.clone());
 15→            if tag.is_expanded && !tag.children.is_empty() {
 16→                Self::collect_visible_tags(&tag.children, visible);
 17→            }
 18→        }
 19→    }
 20→
 21→    pub(super) fn rebuild_visible_tags(&mut self) {
 22→        let source = self.filtered_tags.as_ref().unwrap_or(&self.all_tags);
 23→        self.tags = Self::build_visible_tags_from(source);
 24→    }
 25→
 26→    pub(super) fn active_tags(&self) -> &Vec<DicomTag> {
 27→        self.filtered_tags.as_ref().unwrap_or(&self.all_tags)
 28→    }
 29→
 30→    pub(super) fn active_tags_mut(&mut self) -> &mut Vec<DicomTag> {
 31→        if self.filtered_tags.is_some() {
 32→            self.filtered_tags.as_mut().unwrap()
 33→        } else {
 34→            &mut self.all_tags
 35→        }
 36→    }
 37→
 38→    pub fn expand_selected(&mut self) {
 39→        if let Some(selected_idx) = self.table_state.selected() {
 40→            if selected_idx < self.tags.len() {
 41→                let selected_tag = &self.tags[selected_idx];
 42→                if selected_tag.is_expandable && !selected_tag.is_expanded {
 43→                    let path = self.build_path_to_tag(selected_idx);
 44→                    Self::set_expanded_in_tree(self.active_tags_mut(), &path, true);
 45→                    self.rebuild_visible_tags();
 46→                }
 47→            }
 48→        }
 49→    }
 50→
 51→    pub fn collapse_parent(&mut self) {
 52→        if let Some(selected_idx) = self.table_state.selected() {
 53→            if selected_idx < self.tags.len() {
 54→                let current_depth = self.tags[selected_idx].depth;
 55→
 56→                if current_depth > 0 {
 57→                    for i in (0..selected_idx).rev() {
 58→                        if self.tags[i].depth < current_depth && self.tags[i].is_expanded {
 59→                            let path = self.build_path_to_tag(i);
 60→                            Self::set_expanded_in_tree(self.active_tags_mut(), &path, false);
 61→                            self.rebuild_visible_tags();
 62→                            self.table_state.select(Some(i));
 63→                            break;
 64→                        }
 65→                    }
 66→                }
 67→            }
 68→        }
 69→    }
 70→
 71→    fn build_path_to_tag(&self, visible_idx: usize) -> Vec<usize> {
 72→        let mut path = Vec::new();
 73→        let mut current_idx = 0;
 74→        Self::find_path_to_index(self.active_tags(), visible_idx, &mut current_idx, &mut path);
 75→        path
 76→    }
 77→
 78→    fn find_path_to_index(
 79→        tags: &[DicomTag],
 80→        target_idx: usize,
 81→        current_idx: &mut usize,
 82→        path: &mut Vec<usize>,
 83→    ) -> bool {
 84→        for (i, tag) in tags.iter().enumerate() {
 85→            if *current_idx == target_idx {
 86→                path.push(i);
 87→                return true;
 88→            }
 89→            *current_idx += 1;
 90→
 91→            if tag.is_expanded && !tag.children.is_empty() {
 92→                path.push(i);
 93→                if Self::find_path_to_index(&tag.children, target_idx, current_idx, path) {
 94→                    return true;
 95→                }
 96→                path.pop();
 97→            }
 98→        }
 99→        false
100→    }
101→
102→    fn set_expanded_in_tree(tags: &mut [DicomTag], path: &[usize], expanded: bool) {
103→        if path.is_empty() {
104→            return;
105→        }
106→
107→        let idx = path[0];
108→        if idx >= tags.len() {
109→            return;
110→        }
111→
112→        if path.len() == 1 {
113→            tags[idx].is_expanded = expanded;
114→        } else {
115→            Self::set_expanded_in_tree(&mut tags[idx].children, &path[1..], expanded);
116→        }
117→    }
118→}
