 3→impl App {
 4→    pub(super) fn toggle_preview(&mut self) {
 5→        self.show_preview = !self.show_preview;
 6→
 7→        if self.show_preview && self.preview_image.is_none() && self.preview_error.is_none() {
 8→            self.decode_preview();
 9→        }
10→    }
11→
12→    pub(super) fn decode_preview(&mut self) {
13→        use dicom_pixeldata::PixelDecoder;
14→        use ratatui_image::picker::ProtocolType;
15→
16→        let Some(picker) = &self.picker else {
17→            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
18→            return;
19→        };
20→
21→        if picker.protocol_type() != ProtocolType::Kitty {
22→            self.preview_error = Some("Preview requires a Kitty-compatible terminal".into());
23→            return;
24→        }
25→
26→        let Some(path) = &self.dicom_file_path else {
27→            self.preview_error = Some("No DICOM file path available".into());
28→            return;
29→        };
30→
31→        let obj = match dicom::object::open_file(path) {
32→            Ok(obj) => obj,
33→            Err(e) => {
34→                self.preview_error = Some(format!("Failed to open DICOM file: {e}"));
35→                return;
36→            }
37→        };
38→
39→        let pixel_data = match obj.decode_pixel_data() {
40→            Ok(pd) => pd,
41→            Err(e) => {
42→                self.preview_error = Some(format!("Failed to decode pixel data: {e}"));
43→                return;
44→            }
45→        };
46→
47→        let dyn_img = match pixel_data.to_dynamic_image(0) {
48→            Ok(img) => img,
49→            Err(e) => {
50→                self.preview_error = Some(format!("Failed to convert to image: {e}"));
51→                return;
52→            }
53→        };
54→
55→        let mut picker = self.picker.take().unwrap();
56→        self.preview_image = Some(picker.new_resize_protocol(dyn_img));
57→        self.picker = Some(picker);
58→    }
59→}
