  9→pub fn load_dicom_file<P: AsRef<Path>>(
 10→    path: P,
 11→) -> Result<Vec<DicomTag>, Box<dyn std::error::Error>> {
 12→    let obj = open_file(path)?;
 13→    Ok(extract_tags(&obj))
 14→}
 15→
 16→pub fn extract_tags(obj: &FileDicomObject<InMemDicomObject>) -> Vec<DicomTag> {
 17→    let mut tags = Vec::new();
 18→
 19→    for element in obj.meta().to_element_iter() {
 20→        let tag = element.tag();
 21→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
 22→
 23→        let name = StandardDataDictionary
 24→            .by_tag(tag)
 25→            .map(|entry| entry.alias.to_string())
 26→            .unwrap_or_default();
 27→
 28→        let vr = element.vr().to_string();
 29→        let value = format_value(element.value());
 30→
 31→        tags.push(DicomTag {
 32→            tag: tag_str,
 33→            name,
 34→            vr: vr.to_string(),
 35→            value,
 36→            baseline_value: None,
 37→            depth: 0,
 38→            is_expandable: false,
 39→            is_expanded: false,
 40→            children: Vec::new(),
 41→            diff_status: None,
 42→        });
 43→    }
 44→
 45→    for element in obj {
 46→        let tag = element.tag();
 47→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
 48→
 49→        let name = StandardDataDictionary
 50→            .by_tag(tag)
 51→            .map(|entry| entry.alias.to_string())
 52→            .unwrap_or_default();
 53→
 54→        let vr = element.vr().to_string();
 55→
 56→        let (value, children, is_expandable) = if let Some(items) = element.value().items() {
 57→            let children = extract_sequence_items(items, 1);
 58→            let is_expandable = !children.is_empty();
 59→            let value = format!("<Sequence with {} item(s)>", items.len());
 60→            (value, children, is_expandable)
 61→        } else {
 62→            (format_value(element.value()), Vec::new(), false)
 63→        };
 64→
 65→        tags.push(DicomTag {
 66→            tag: tag_str,
 67→            name,
 68→            vr: vr.to_string(),
 69→            value,
 70→            baseline_value: None,
 71→            depth: 0,
 72→            is_expandable,
 73→            is_expanded: false,
 74→            children,
 75→            diff_status: None,
 76→        });
 77→    }
 78→
 79→    tags
 80→}
 81→
 82→fn extract_sequence_items(items: &[InMemDicomObject], depth: usize) -> Vec<DicomTag> {
 83→    let mut children = Vec::new();
 84→
 85→    for (item_idx, item) in items.iter().enumerate() {
 86→        let item_children = extract_tags_from_inmem_object(item, depth + 1);
 87→        let item_header = DicomTag {
 88→            tag: format!("Item #{}", item_idx + 1),
 89→            name: String::new(),
 90→            vr: String::new(),
 91→            value: format!("<{} element(s)>", item.into_iter().count()),
 92→            baseline_value: None,
 93→            depth,
 94→            is_expandable: !item_children.is_empty(),
 95→            is_expanded: false,
 96→            children: item_children,
 97→            diff_status: None,
 98→        };
 99→        children.push(item_header);
100→    }
101→
102→    children
103→}
104→
105→fn extract_tags_from_inmem_object(obj: &InMemDicomObject, depth: usize) -> Vec<DicomTag> {
106→    let mut tags = Vec::new();
107→
108→    for element in obj {
109→        let tag = element.tag();
110→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
111→
112→        let name = StandardDataDictionary
113→            .by_tag(tag)
114→            .map(|entry| entry.alias.to_string())
115→            .unwrap_or_default();
116→
117→        let vr = element.vr().to_string();
118→
119→        let (value, children, is_expandable) = if let Some(items) = element.value().items() {
120→            let children = extract_sequence_items(items, depth + 1);
121→            let is_expandable = !children.is_empty();
122→            let value = format!("<Sequence with {} item(s)>", items.len());
123→            (value, children, is_expandable)
124→        } else {
125→            (format_value(element.value()), Vec::new(), false)
126→        };
127→
128→        tags.push(DicomTag {
129→            tag: tag_str,
130→            name,
131→            vr: vr.to_string(),
132→            value,
133→            baseline_value: None,
134→            depth,
135→            is_expandable,
136→            is_expanded: false,
137→            children,
138→            diff_status: None,
139→        });
140→    }
141→
142→    tags
143→}
144→
145→fn format_value<I: HasLength, P>(value: &dicom::core::value::Value<I, P>) -> String {
146→    let value_str = if value.primitive().is_some() {
147→        value
148→            .to_str()
149→            .map(|c| c.into_owned())
150→            .unwrap_or_else(|_| "<Error>".to_string())
151→    } else if let Some(seq) = value.items() {
152→        format!("<Sequence with {} item(s)>", seq.len())
153→    } else if value.fragments().is_some() {
154→        "<Pixel Data Sequence>".to_string()
155→    } else {
156→        "<Unknown>".to_string()
157→    };
158→
159→    truncate_value(&value_str, 256)
160→}
161→
162→fn truncate_value(s: &str, max_len: usize) -> String {
163→    if s.len() > max_len {
164→        format!("{}...", &s[..max_len])
165→    } else {
166→        s.to_string()
167→    }
168→}
